updated AS (
  UPDATE "Customer" c
  SET
    code = CASE WHEN c.code IS NULL OR btrim(c.code) = '' THEN s.code ELSE c.code END,
    phone = CASE WHEN NULLIF(s.phone, '') IS NOT NULL THEN s.phone ELSE c.phone END,
    email = CASE WHEN NULLIF(s.email, '') IS NOT NULL THEN s.email ELSE c.email END,
    "billingAddress" = CASE WHEN NULLIF(s.billing_address, '') IS NOT NULL THEN s.billing_address ELSE c."billingAddress" END,
    "shippingAddress" = CASE WHEN NULLIF(s.shipping_address, '') IS NOT NULL THEN s.shipping_address ELSE c."shippingAddress" END,
    "taxId" = CASE WHEN NULLIF(s.tax_id, '') IS NOT NULL THEN s.tax_id ELSE c."taxId" END,
    "creditLimit" = CASE WHEN NULLIF(s.credit_limit, '') IS NOT NULL THEN s.credit_limit::numeric ELSE c."creditLimit" END,
    "paymentTermDays" = CASE WHEN NULLIF(s.payment_term_days, '') IS NOT NULL THEN s.payment_term_days::integer ELSE c."paymentTermDays" END,
    "discountPercent" = CASE WHEN NULLIF(s.discount_percent, '') IS NOT NULL THEN s.discount_percent::numeric ELSE c."discountPercent" END,
    notes = CASE
      WHEN NULLIF(s.notes, '') IS NULL THEN c.notes
      WHEN c.notes IS NULL OR btrim(c.notes) = '' THEN s.notes
      WHEN position(s.notes in c.notes) > 0 THEN c.notes
      ELSE c.notes || ' | ' || s.notes
    END,
    "isActive" = CASE WHEN lower(s.is_active) = 'true' THEN true ELSE c."isActive" END,
    "updatedAt" = NOW()
  FROM staging s
  WHERE c.name = s.name
  RETURNING c.name
),
inserted AS (
  INSERT INTO "Customer" (
    id, name, code, phone, email, "billingAddress", "shippingAddress", "taxId",
    "creditLimit", "paymentTermDays", "discountPercent", notes, "isActive", "createdAt", "updatedAt"
  )
  SELECT
    gen_random_uuid()::text,
    s.name,
    s.code,
    NULLIF(s.phone, ''),
    NULLIF(s.email, ''),
    NULLIF(s.billing_address, ''),
    NULLIF(s.shipping_address, ''),
    NULLIF(s.tax_id, ''),
    CASE WHEN NULLIF(s.credit_limit, '') IS NOT NULL THEN s.credit_limit::numeric ELSE NULL END,
    CASE WHEN NULLIF(s.payment_term_days, '') IS NOT NULL THEN s.payment_term_days::integer ELSE NULL END,
    CASE WHEN NULLIF(s.discount_percent, '') IS NOT NULL THEN s.discount_percent::numeric ELSE NULL END,
    NULLIF(s.notes, ''),
    CASE WHEN lower(s.is_active) = 'true' THEN true ELSE false END,
    NOW(),
    NOW()
  FROM staging s
  WHERE NOT EXISTS (
    SELECT 1 FROM "Customer" c WHERE c.name = s.name
  )
  RETURNING name
)
SELECT
  (SELECT COUNT(*) FROM staging) AS staging_rows,
  (SELECT COUNT(*) FROM updated) AS updated_rows,
  (SELECT COUNT(*) FROM inserted) AS inserted_rows;

COMMIT;
